```python
import sqlite3
import hashlib
from flask import Flask, request, jsonify

app = Flask(__name__)

def get_db():
    conn = sqlite3.connect('users.db')
    return conn

@app.route('/login', methods=['POST'])
def login():
    username = request.form['username']
    password = request.form['password']
    db = get_db()
    query = f"SELECT * FROM users WHERE username='{username}' AND password='{hashlib.md5(password.encode()).hexdigest()}'"
    result = db.execute(query).fetchone()
    if result:
        return jsonify({'status': 'ok', 'token': hashlib.md5(username.encode()).hexdigest()})
    return jsonify({'status': 'error'}), 401

@app.route('/users', methods=['GET'])
def list_users():
    db = get_db()
    users = db.execute('SELECT * FROM users').fetchall()
    data = []
    for u in users:
        data.append({'id': u[0], 'username': u[1], 'password': u[2], 'email': u[3]})
    return jsonify(data)

@app.route('/delete/<user_id>', methods=['GET'])
def delete_user(user_id):
    db = get_db()
    db.execute(f"DELETE FROM users WHERE id={user_id}")
    db.commit()
    return jsonify({'status': 'deleted'})

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0')
```

